#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < Q; i++) {
            int L, R, K;
            scanf("%d %d %d", &L, &R, &K);
            int count = 0;
            for (int j = L - 1; j < R; j++) {
                if (A[j] % K == 0) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

