import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < Q; i++) {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int K = sc.nextInt();
                int count = 0;
                for (int j = L - 1; j < R; j++) {
                    if (A[j] % K == 0) {
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

